import{_ as e,V as a,W as s,a1 as n}from"./framework.46148295.js";const t={},r=n(`<h1 id="testcontainers" tabindex="-1"><a class="header-anchor" href="#testcontainers" aria-hidden="true">#</a> Testcontainers</h1><h2 id="连接远程docker" tabindex="-1"><a class="header-anchor" href="#连接远程docker" aria-hidden="true">#</a> 连接远程Docker</h2><h3 id="背景" tabindex="-1"><a class="header-anchor" href="#背景" aria-hidden="true">#</a> 背景</h3><p>本地开发使用windows系统，使用Testcontainers 进行集成测试时需要连接Docker，而Docker for windows版本要求开启Hyper-v，Hyper-v与vmware是冲突的，不升级硬件的情况下只能使用其中一个。于是想到在本地连接虚拟机上的Docker进行测试 ​</p><h3 id="docker-server远程链接配置" tabindex="-1"><a class="header-anchor" href="#docker-server远程链接配置" aria-hidden="true">#</a> Docker Server远程链接配置</h3><p>​</p><ol><li>在/etc/docker/daemon.json中开启远程链接端口</li></ol><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span><span class="token property">&quot;hosts&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;tcp://0.0.0.0:2375&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;unix:///var/run/docker.sock&quot;</span><span class="token punctuation">]</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="2"><li>添加文件/etc/systemd/system/docker.service.d/override.conf​</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code> [Service]
 ExecStart=
 ExecStart=/usr/bin/dockerd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><em>注意上述路径不存在则手动创建</em><em>​</em></p><ol start="3"><li>重启dock容器</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$ sudo systemctl daemon-reload # 重载守护进程
$ sudo systemctl restart docker # 重启docker容器
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="4"><li>在客户端测试连接</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$ docker -H 192.168.57.110:2375 info
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>成功输出信息，证明客户端可以成功连接到远程的服务端。</p><h3 id="设置-docker-host" tabindex="-1"><a class="header-anchor" href="#设置-docker-host" aria-hidden="true">#</a> 设置 DOCKER_HOST</h3><h4 id="方式一-修改环境变量" tabindex="-1"><a class="header-anchor" href="#方式一-修改环境变量" aria-hidden="true">#</a> 方式一：修改环境变量</h4><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>DOCKER_HOST=tcp://remote_docker_server_ip:2375
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="方式二-直接在java测试代码中-构造容器前-通过代码" tabindex="-1"><a class="header-anchor" href="#方式二-直接在java测试代码中-构造容器前-通过代码" aria-hidden="true">#</a> 方式二：直接在java测试代码中，构造容器前，通过代码</h4><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">System</span><span class="token punctuation">.</span><span class="token function">setProperty</span><span class="token punctuation">(</span><span class="token string">&quot;DOCKER_HOST&quot;</span><span class="token punctuation">,</span><span class="token string">&quot;tcp://remote_docker_server_ip:2375&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="方式三-如果集成测试使用maven-failsafe插件-则在插件上配置环境变量" tabindex="-1"><a class="header-anchor" href="#方式三-如果集成测试使用maven-failsafe插件-则在插件上配置环境变量" aria-hidden="true">#</a> 方式三：如果集成测试使用maven failsafe插件，则在插件上配置环境变量</h4>`,22),i=[r];function d(c,o){return a(),s("div",null,i)}const u=e(t,[["render",d],["__file","testcontainers.html.vue"]]);export{u as default};
